example.code:
upstream web_backend {
    # round-robin is the default in Nginx — no directive needed
    server 10.0.0.1:8080 weight=5 max_fails=3 fail_timeout=30s;
    server 10.0.0.2:8080 weight=5 max_fails=3 fail_timeout=30s;
    server 10.0.0.3:8080 weight=2 backup;
    keepalive 32;
}

upstream api_backend {
    ip_hash;  # DO NOT use with autoscaling
    server 10.0.1.1:8000;
    server 10.0.1.2:8000;
    server 10.0.1.3:8000;
}
# Problem: scale-in event removes one server → all sessions redistribute
# Problem: corporate NAT → one IP maps to thousands of real users
